--
-- Table structure for table `posts`
--

DROP TABLE IF EXISTS `posts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `posts` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int(10) unsigned NOT NULL,
  `title` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `category_id` int(10) unsigned DEFAULT NULL,
  `location` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `topics` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `post_type` tinyint(4) NOT NULL DEFAULT '3' COMMENT '1文字 2语音 3图文',
  `voice_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `voice_duration` int(10) unsigned NOT NULL DEFAULT '0',
  `text_template` tinyint(4) NOT NULL DEFAULT '0',
  `link` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `content_blocks` json DEFAULT NULL COMMENT '块编辑器内容',
  `likes_count` int(10) unsigned NOT NULL DEFAULT '0',
  `collects_count` int(10) unsigned NOT NULL DEFAULT '0',
  `comments_count` int(10) unsigned NOT NULL DEFAULT '0',
  `views_count` int(10) unsigned NOT NULL DEFAULT '0',
  `shares_count` int(10) unsigned NOT NULL DEFAULT '0',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '0下架 1正常 2审核中',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_pinned` tinyint(4) NOT NULL DEFAULT '0' COMMENT '0普通 1置顶',
  `pinned_at` datetime DEFAULT NULL COMMENT '置顶时间',
  `pinned_category_id` int(10) unsigned DEFAULT NULL COMMENT '在哪个分类置顶',
  `is_private` tinyint(4) NOT NULL DEFAULT '0' COMMENT '0公开 1私密',
  PRIMARY KEY (`id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_status` (`status`),
  KEY `idx_created` (`created_at`),
  CONSTRAINT `posts_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

